// Bridge the two forall|lo, hi| quantifiers from the ensures clauses
// (run-1 triggers on `post1_self_.gap(lo, hi)`, run-2 on `post2_self_.gap(lo, hi)`;
// without this `assert forall ... by`, z3 never instantiates them at the same `lo, hi`).
assert forall|lo: KeyIterator<K>, hi: KeyIterator<K>|
    post1_self_.gap(lo, hi) == post2_self_.gap(lo, hi) by {
    // Inside the `by` block both gap expressions appear in the goal, so both
    // ensures-foralls fire and reduce to the same RHS
    //   pre_self_.gap(lo, hi) && !(lo.lt_spec(KeyIterator::new_spec(k))
    //                          && KeyIterator::new_spec(k).lt_spec(hi))
    // making them equal by transitivity.
}

// View equality follows by transitivity through `pre_self_@.insert(k, v)`,
// which both post views are equal to per the ensures clause.
assert(post1_self_@ == pre_self_@.insert(k, v));
assert(post2_self_@ == pre_self_@.insert(k, v));
assert(post1_self_@ == post2_self_@);
